mapper.select:
select m.id, m.stock_id, m.current_price, m.dividend_per_share, m.calculated_yield, m.data_time, m.create_time, s.stock_code, s.stock_name from stock_market_data m left join stock_basic s on m.stock_id = s.stock_id
AND m.stock_id = #{stockId}
AND s.stock_code = #{stockCode}
order by m.data_time DESC
